package ir.tahamohamadi.blog.post;
import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import org.hibernate.annotations.ColumnTransformer; import java.time.Instant; import java.util.*;
@Entity @Table(name="blog_post_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogPostTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="blog_post_id",nullable=false) private BlogPost blogPost; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false,length=255) private String title; @Column(nullable=false,length=255) private String slug; @Column(columnDefinition="text") private String excerpt; @Column(name="body_markdown",nullable=false,columnDefinition="text") private String bodyMarkdown; @Column(name="seo_title",length=255) private String seoTitle; @Column(name="seo_description",length=500) private String seoDescription; @Column(name="search_vector", insertable=false, updatable=false, columnDefinition="tsvector") private String searchVector; private BlogPostTranslation(UUID id,BlogPost post,LanguageCode lang,String title,String slug,String body,Instant at){initialize(id,at);blogPost=Objects.requireNonNull(post);languageCode=Objects.requireNonNull(lang);this.title=requireNonBlank(title,"title");this.slug=requireNonBlank(slug,"slug");bodyMarkdown=requireNonBlank(body,"bodyMarkdown");} public static BlogPostTranslation create(UUID id,BlogPost post,LanguageCode lang,String title,String slug,String body,Instant at){return new BlogPostTranslation(id,post,lang,title,slug,body,at);} public void update(String title,String slug,String excerpt,String body,String seoTitle,String seoDescription){this.title=requireNonBlank(title,"title");this.slug=requireNonBlank(slug,"slug");this.excerpt=excerpt;this.bodyMarkdown=requireNonBlank(body,"bodyMarkdown");this.seoTitle=seoTitle;this.seoDescription=seoDescription;} }
